client_script:
console.log("✅ Web Form script loaded");

function fetch_and_set_fare(flight) {
    if (!flight) {
        frappe.web_form.set_value('fare', '');
        return;
    }

    frappe.call({
        method: "airplane_mode.api.get_fare_for_flight",
        args: { flight },
        callback(r) {
            console.log("💰 Fare API response:", r);

            if (r.message !== undefined) {
                frappe.web_form.set_value('fare', r.message);
            }
        }
    });
}

// When flight is changed manually
frappe.web_form.on('flight', () => {
    console.log("✈️ Flight changed");
    const flight = frappe.web_form.get_value('flight');
    fetch_and_set_fare(flight);
});

// When page loads with ?flight=xxx
frappe.web_form.on('load', () => {
    const flight = frappe.utils.get_url_arg('flight');
    console.log("🔗 Flight from URL:", flight);

    if (flight) {
        frappe.web_form.set_value('flight', flight);
        fetch_and_set_fare(flight);
    }
});
